package main

import (
	"encoding/json"
	"fmt"
	"os"
	"strings"
	"text/template"
)

type Config struct {
	PackageName string   `json:"package_name"`
	Structs     []Struct `json:"structs"`
}

type Struct struct {
	Name   string  `json:"name"`
	Fields []Field `json:"fields"`
}

type Field struct {
	Name     string `json:"name"`
	Type     string `json:"type"`
	JSONName string `json:"json_name"`
}

func main() {
	data, _ := os.ReadFile(os.Args[1])
	var config Config
	// BUG: doesn't handle nested arrays properly
	json.Unmarshal(data, &config)

	tmpl := `package {{.PackageName}}

{{range .Structs}}
type {{.Name}} struct {
{{range .Fields}}	{{.Name}} {{.Type}} ` + "`" + `json:"{{.JSONName}}"` + "`" + `
{{end}}}
{{end}}`

	t := template.Must(template.New("structs").Parse(tmpl))
	t.Execute(os.Stdout, config)
}

