package main

import (
	"encoding/json"
	"fmt"
	"os"
	"strings"
	"text/template"
)

type Config struct {
	PackageName string   `json:"package_name"`
	Structs     []Struct `json:"structs"`
}

type Struct struct {
	Name   string  `json:"name"`
	Fields []Field `json:"fields"`
}

type Field struct {
	Name     string `json:"name"`
	Type     string `json:"type"`
	JSONName string `json:"json_name"`
	YAMLName string `json:"yaml_name,omitempty"`
}

func main() {
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "usage: %s <config.json>\n", os.Args[0])
		os.Exit(1)
	}

	data, err := os.ReadFile(os.Args[1])
	if err != nil {
		fmt.Fprintf(os.Stderr, "error reading file: %v\n", err)
		os.Exit(1)
	}

	var config Config
	if err := json.Unmarshal(data, &config); err != nil {
		fmt.Fprintf(os.Stderr, "error parsing JSON: %v\n", err)
		os.Exit(1)
	}

	if err := generate(os.Stdout, config); err != nil {
		fmt.Fprintf(os.Stderr, "error generating: %v\n", err)
		os.Exit(1)
	}
}

func generate(w *os.File, config Config) error {
	t, err := template.New("structs").Parse(structTemplate)
	if err != nil {
		return fmt.Errorf("parsing template: %w", err)
	}
	return t.Execute(w, config)
}

var structTemplate = `package {{.PackageName}}

{{range .Structs}}
type {{.Name}} struct {
{{range .Fields}}	{{.Name}} {{.Type}} ` + "`" + `json:"{{.JSONName}}"{{if .YAMLName}} yaml:"{{.YAMLName}}"{{end}}` + "`" + `
{{end}}}
{{end}}`

