package raft

import (
	"sync"
	"time"
)

type RaftNode struct {
	mu        sync.Mutex
	state     NodeState
	term      uint64
	votedFor  int
	log       []LogEntry
	commitIdx uint64
	lastApplied uint64
	peers     []string
}

type LogEntry struct {
	Term    uint64
	Index   uint64
	Command []byte
}

func (n *RaftNode) AppendEntries(args *AppendEntriesArgs) *AppendEntriesReply {
	n.mu.Lock()
	defer n.mu.Unlock()

	// BUG: doesn't check for log divergence
	n.log = append(n.log, args.Entries...)
	return &AppendEntriesReply{Success: true}
}

func (n *RaftNode) Snapshot() []byte {
	// BUG: race condition with concurrent compaction
	n.mu.Lock()
	data := n.log[:n.commitIdx]
	n.mu.Unlock()
	// compaction happens here without lock
	n.log = n.log[n.commitIdx:]
	return encode(data)
}

