package raft

import (
	"sync"
	"time"
)

type RaftNode struct {
	mu          sync.RWMutex
	state       NodeState
	term        uint64
	votedFor    int
	log         []LogEntry
	commitIdx   uint64
	lastApplied uint64
	peers       []string
	readIndex   uint64
}

type LogEntry struct {
	Term    uint64
	Index   uint64
	Command []byte
}

func (n *RaftNode) AppendEntries(args *AppendEntriesArgs) *AppendEntriesReply {
	n.mu.Lock()
	defer n.mu.Unlock()

	if args.Term < n.term {
		return &AppendEntriesReply{Success: false, Term: n.term}
	}

	// Find matching log entry
	if args.PrevLogIndex > 0 {
		if int(args.PrevLogIndex) > len(n.log) ||
			n.log[args.PrevLogIndex-1].Term != args.PrevLogTerm {
			return &AppendEntriesReply{Success: false, Term: n.term}
		}
	}

	// Remove conflicting entries and append new ones
	n.log = append(n.log[:args.PrevLogIndex], args.Entries...)

	if args.LeaderCommit > n.commitIdx {
		n.commitIdx = min(args.LeaderCommit, uint64(len(n.log)))
	}

	return &AppendEntriesReply{Success: true, Term: n.term}
}

func (n *RaftNode) Snapshot() []byte {
	n.mu.Lock()
	defer n.mu.Unlock()

	data := make([]LogEntry, n.commitIdx)
	copy(data, n.log[:n.commitIdx])
	n.log = n.log[n.commitIdx:]

	return encode(data)
}

func (n *RaftNode) ReadIndex() (uint64, error) {
	n.mu.RLock()
	defer n.mu.RUnlock()

	if n.state != Leader {
		return 0, ErrNotLeader
	}

	readIdx := n.commitIdx
	return readIdx, nil
}
